import { type ClassValue, clsx } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

/**
 * Generate a Gravatar URL for the given email address
 * @param email The email address to generate a Gravatar for
 * @param size The size of the Gravatar in pixels
 * @param defaultImage The default image to use if no Gravatar exists ('mp', 'identicon', 'monsterid', 'wavatar', 'retro', 'robohash', 'blank', or a URL)
 * @returns The Gravatar URL
 */
export async function getGravatarUrl(
  email: string,
  size = 80,
  defaultImage = "mp",
) {
  // Handle undefined, null or empty email cases
  if (!email || email.trim() === "") {
    return `https://gravatar.com/avatar/00000000000000000000000000000000?s=${size.toString()}&d=${defaultImage}`;
  }

  // Trim leading/trailing whitespace and convert to lowercase
  const normalizedEmail = email.trim().toLowerCase();

  // Create MD5 hash of the normalized email
  const hashBuffer = await crypto.subtle.digest(
    "SHA-256",
    new TextEncoder().encode(normalizedEmail),
  );

  // Convert ArrayBuffer to hex string
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  const emailHash = hashArray
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");

  // Return the Gravatar URL with the MD5 hash
  return `https://gravatar.com/avatar/${emailHash}?s=${size.toString()}&d=${defaultImage}`;
}

// Returns a random color in hex format.
export const getRandomColor = () => {
  let color = Math.floor(Math.random() * 16777215).toString(16);

  // Math.random will sometimes produce a decimal that results in 5 instead of 6 digits
  while (color.length < 6) {
    color += "0";
  }

  return `#${color}`;
};

export const getContrastColor = (
  color?: string,
  options?: {
    dark?: string;
    light?: string;
  },
) => {
  const dark = options?.dark ?? "hsl(var(--foreground))";
  const light = options?.light ?? "hsl(var(--background))";

  if (!color) {
    return dark;
  }

  const colorToSample = color.replace("#", "");

  const R = Number.parseInt(colorToSample.slice(0, 2), 16);
  const G = Number.parseInt(colorToSample.slice(2, 4), 16);
  const B = Number.parseInt(colorToSample.slice(4, 6), 16);

  // https://stackoverflow.com/a/3943023
  return R * 0.299 + G * 0.587 + B * 0.114 > 150 ? dark : light;
};

export const convertToKB = (bytes: number) => {
  return bytes / 1024;
};

export const convertToMB = (bytes: number) => {
  return bytes / 1024 ** 2;
};

export const formatBytes = (bytes?: number) => {
  if (!bytes || bytes < 0) {
    return "";
  }

  if (bytes < 10) {
    return `${bytes} bytes`;
  }

  if (bytes < 900) {
    return `${convertToKB(bytes).toFixed(2)} KB`;
  }

  if (bytes < 1024 ** 2) {
    return `${convertToKB(bytes).toFixed(0)} KB`;
  }

  return `${convertToMB(bytes).toFixed(0)} MB`;
};

